        assert!(config.multi_process);
        assert!(config.sandbox);
        assert!(!config.incognito);
        assert_eq!(config.user_data_dir, config.data_dirs.profile_dir);
    }

    #[test]
    fn test_config_incognito() {
        let config = BrowserConfig::incognito();
        assert!(config.incognito);
        assert!(config.sandbox);
        assert_eq!(config.user_data_dir, config.data_dirs.profile_dir);
    }
}

