/// GPU process (runs in child process)
pub struct GpuProcess {
    channel_id: String,
}

impl GpuProcess {
    pub async fn new(channel_id: &str) -> Self {
        info!("GPU process initializing with channel: {}", channel_id);
        GpuProcess {
            channel_id: channel_id.to_string(),
        }
    }

    pub async fn run(&self) {
        info!("GPU process running on channel {}", self.channel_id);
        use crate::ipc::{self, IpcReceiver};
        use crate::ipc::GpuMessage;

        // ponytail: single-channel, in-order message processing
        match IpcReceiver::<GpuMessage>::connect(self.channel_id.clone()) {
            Ok(rx) => {
                while let Ok(msg) = rx.recv() {
                    match msg {
                        GpuMessage::SubmitFrame {
                            tab_id,
                            surface_id,
                            frame_id,
                        } => {
                            info!("GPU: tab {} submitted frame {} surface {:?}", tab_id, frame_id, surface_id.0);
                        }
                        GpuMessage::Present { tab_id, surface_id } => {
                            info!("GPU: presenting tab {} surface {:?}", tab_id, surface_id);
                        }
                    }
                }
            }
            Err(e) => {
                log::error!("GPU process failed to connect to IPC channel: {}", e);
            }
        }
    }
}

