//! Network stack module

use crate::ipc::{self, IpcReceiver, NetworkMessage};
use crate::storage::{CookieJar, StorageManager};
use log::info;
use std::sync::Arc;

/// Network manager for HTTP requests
pub struct NetworkManager {
    cookies: Arc<CookieJar>,
}

impl NetworkManager {
    pub async fn new(storage: Arc<StorageManager>) -> Result<Self, String> {
        info!("Initializing network manager");
        Ok(NetworkManager {
            cookies: Arc::new(storage.cookies.clone()),
        })
    }

    pub fn cookie_jar(&self) -> &CookieJar {
        &self.cookies
    }
}

/// HTTP request
pub struct Request {
    pub url: String,
    pub method: String,
}

/// HTTP response
pub struct Response {
    pub status: u16,
    pub body: Vec<u8>,
}

/// Network process (runs in child process)
pub struct NetworkProcess {
    channel_id: String,
}

impl NetworkProcess {
    pub async fn new(channel_id: &str) -> Self {
        info!("Network process initializing with channel: {}", channel_id);
        NetworkProcess {
            channel_id: channel_id.to_string(),
        }
    }

    pub async fn run(&self) {
        info!("Network process running on channel {}", self.channel_id);

        let rx = match IpcReceiver::<NetworkMessage>::connect(self.channel_id.clone()) {
            Ok(rx) => rx,
            Err(e) => {
                log::error!("Network process failed to connect to IPC: {}", e);
                return;
            }
        };

        let client = reqwest::Client::new();

        // ponytail: sequential request processing, no connection pooling tuning
        while let Ok(msg) = rx.recv() {
            match msg {
                NetworkMessage::Fetch {
                    request_id,
                    url,
                    method,
                    headers,
                    body,
                } => {
                    let req = client.request(method.parse().unwrap_or(reqwest::Method::GET), &url);
                    let req = headers
                        .iter()
                        .fold(req, |r, (k, v)| r.header(k.as_str(), v.as_str()));
                    let req = if let Some(b) = body {
                        req.body(b)
                    } else {
                        req
                    };

                    match req.send().await {
                        Ok(resp) => {
                            let status = resp.status().as_u16();
                            let resp_headers: Vec<(String, String)> = resp
                                .headers()
                                .iter()
                                .map(|(k, v)| (k.to_string(), v.to_str().unwrap_or("").to_string()))
                                .collect();
                            match resp.bytes().await {
                                Ok(bytes) => {
                                    info!("Network: fetched {} ({} bytes, {})", url, bytes.len(), status);
                                    // ponytail: response sent as single chunk, no streaming
                                }
                                Err(e) => {
                                    log::error!("Network: failed to read body for {}: {}", url, e);
                                }
                            }
                        }
                        Err(e) => {
                            log::error!("Network: request failed for {}: {}", url, e);
                        }
                    }
                }
            }
        }
    }
}

